#include <stdio.h>

int* nextGreaterElements(int* arr, int arrSize) {
    int* ans = (int*)malloc(arrSize * sizeof(int));
    for (int i = 0; i < arrSize; i++) {
        ans[i] = -1;
        for (int j = 1; j < arrSize; j++) {
            int ind = (j + i) % arrSize;
            if (arr[ind] > arr[i]) {
                ans[i] = arr[ind];
                break;
            }
        }
    }
    return ans;
}

int main() {
    int arr[] = {3, 10, 4, 2, 1, 2, 6, 1, 7, 2, 9};
    int arrSize = sizeof(arr) / sizeof(arr[0]);
    int* ans = nextGreaterElements(arr, arrSize);
    for (int i = 0; i < arrSize; i++) {
        printf("%d ", ans[i]);
    }
    return 0;
}

