#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> nextGreaterElements(vector<int> arr) {
        int n = arr.size();
        vector<int> ans(n, -1);
        for (int i = 0; i < n; i++) {
            for (int j = 1; j < n; j++) {
                int ind = (j + i) % n;
                if (arr[ind] > arr[i]) {
                    ans[i] = arr[ind];
                    break;
                }
            }
        }
        return ans;
    }
};

int main() {
    Solution sol;
    vector<int> arr = {3, 10, 4, 2, 1, 2, 6, 1, 7, 2, 9};
    vector<int> ans = sol.nextGreaterElements(arr);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << " ";
    }
    return 0;
}

